function solve(chunks: string[], queries: string[]): number[] {
    // 1. Concatenate chunks into s
    const s = chunks.join('');

    // 2. Find all maximal contiguous sequences of lowercase English letters (words)
    // Based on the provided examples, any non-letter character (including '-') acts as a separator.
    const words: string[] = [];
    // Regex matches sequences of one or more lowercase letters
    const regex = /[a-z]+/g;
    let match: RegExpExecArray | null;

    while ((match = regex.exec(s)) !== null) {
        words.push(match[0]);
    }

    // 3. Count frequencies of each word
    const wordCounts = new Map<string, number>();
    for (const word of words) {
        wordCounts.set(word, (wordCounts.get(word) || 0) + 1);
    }

    // 4. Generate the result array for queries
    const ans: number[] = [];
    for (const query of queries) {
        // Since the problem guarantees queries[i] is a valid word structure, 
        // we just look up its count.
        ans.push(wordCounts.get(query) || 0);
    }

    return ans;
}
