function solve(chunks: string[], queries: string[]): number[] {
    // 1. Construct s
    const s = chunks.join('');

    // 2. Initialize word counts
    const wordCounts: Map<string, number> = new Map();

    // Helper function to check if a character is a lowercase letter
    const isLetter = (char: string): boolean => {
        if (char.length !== 1) return false;
        const code = char.charCodeAt(0);
        return (code >= 'a'.charCodeAt(0) && code <= 'z'.charCodeAt(0));
    };

    const recordWord = (word: string) => {
        wordCounts.set(word, (wordCounts.get(word) || 0) + 1);
    };

    // 3. Parse s to find all maximal valid words
    let W = "";
    let i = 0;
    const N = s.length;

    while (i < N) {
        const char = s[i];

        if (isLetter(char)) {
            W += char;
            i++;
        } else if (char === '-') {
            // Check legality: 
            // 1. W must end in a letter.
            // 2. s[i+1] must be a letter.

            const W_ends_in_letter = W.length > 0 && isLetter(W[W.length - 1]);
            const nextCharIsLetter = i + 1 < N && isLetter(s[i+1]);

            if (W_ends_in_letter && nextCharIsLetter) {
                // Legal hyphen
                W += '-';
                i++;
            } else {
                // Illegal hyphen acts as separator
                if (W.length > 0) {
                    recordWord(W);
                    W = "";
                }
                i++; // Skip the illegal hyphen
            }
        } else { 
            // General separator (space, etc.)

            // Finalize W if non-empty
            if (W.length > 0) {
                recordWord(W);
                W = "";
            }
            i++;
        }
    }

    // Handle trailing word
    if (W.length > 0) {
        recordWord(W);
    }

    // 4. Answer queries
    const results: number[] = [];
    for (const query of queries) {
        results.push(wordCounts.get(query) || 0);
    }

    return results;
}
