function solve(chunks: string[], queries: string[]): number[] {
    // 1. Construct s
    const s = chunks.join('');

    // 2. Initialize word counts
    const wordCounts: Map<string, number> = new Map();

    // Helper function to check if a character is a lowercase letter
    const isLetter = (char: string): boolean => {
        if (char.length !== 1) return false;
        const code = char.charCodeAt(0);
        return (code >= 'a'.charCodeAt(0) && code <= 'z'.charCodeAt(0));
    };

    const recordWord = (word: string) => {
        wordCounts.set(word, (wordCounts.get(word) || 0) + 1);
    };

    // 3. Parse s to find all maximal valid words
    let W = "";
